	@Test
	void exactLeafProbeRequiresTierAndDecisionPermission() {
		AtomicBoolean exactInvoked = new AtomicBoolean();
		RecordingEvidenceSource source = new RecordingEvidenceSource() {
			@Override
			public Optional<EstimateCandidate> exactCandidate(TupleExpr expression, EstimateContext context) {
				exactInvoked.set(true);
				BagEstimate exact = BagEstimate.exact(7.0d, "exact_storage");
				return Optional.of(new EstimateCandidate(exact,
						new RowEvidence(7.0d, 7.0d, 7.0d, 1.0d, true, IDENTITY, 4L, "exact_storage"),
						EstimateCandidate.Kind.EXACT_STORAGE, 2L));
			}
		};
		LmdbEstimationEngine engine = new LmdbEstimationEngine(source, new EstimateEvidenceResolver());
		StatementPattern pattern = pattern("s", P1, "x");
		EstimateContext root = EstimateContext.root(pattern, IDENTITY, 4L).withExactProbePermission(true);

		engine.estimate(pattern, root);
		assertFalse(exactInvoked.get());

		BagEstimate exact = engine.estimate(pattern,
				root.withEstimationTier(
						org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinFactorCostModel.EstimationTier.DECISION_EXACT));
		assertTrue(exactInvoked.get());
		assertEquals(7.0d, exact.rows());
	}

